"""
📊 ORDER FLOW SIGNAL GENERATOR v2
Fixed: stricter entry, wider SL, less divergence sensitivity, cooldown
"""
from orderflow import OrderFlowEngine
import time

class FlowSignal:
    def __init__(self):
        self.ofe = OrderFlowEngine()
        self.last_trade_time = 0
        self.min_cooldown = 120  # minimum 2 menit antar trade

    def generate(self, data=None):
        if data is None:
            data = self.ofe.analyze()
        if data is None:
            return {'signal': 'SKIP', 'reason': 'No data'}

        reasons = []
        filters = []

        price = data['price']
        now = time.time()

        # ========================
        # FILTER 1: Cooldown
        # ========================
        if now - self.last_trade_time < self.min_cooldown:
            remaining = int(self.min_cooldown - (now - self.last_trade_time))
            return {
                'signal': 'WAIT', 'reason': f'Cooldown {remaining}s',
                'filters': filters, 'data': data
            }

        # ========================
        # FILTER 2: OI Extreme = SKIP
        # ========================
        if data['oi']['is_extreme']:
            filters.append(f"OI extreme ({data['oi']['change_pct']:+.1f}%)")
            return {
                'signal': 'SKIP', 'reason': 'OI extreme — market liar',
                'filters': filters, 'data': data
            }

        # ========================
        # FILTER 3: CVD Divergence = EXIT (only if in position)
        # ========================
        if data['cvd_divergence']['divergence']:
            div = data['cvd_divergence']
            # Only trigger if divergence is STRONG
            if abs(div.get('cvd_delta', 0)) > 0.05:
                if div['type'] == 'BEARISH':
                    return {'signal': 'EXIT', 'direction': 'CLOSE_LONG',
                        'reason': f"CVD bearish div (CVD {div['cvd_delta']:+.4f})",
                        'filters': filters, 'data': data}
                elif div['type'] == 'BULLISH':
                    return {'signal': 'EXIT', 'direction': 'CLOSE_SHORT',
                        'reason': f"CVD bullish div (CVD {div['cvd_delta']:+.4f})",
                        'filters': filters, 'data': data}

        # ========================
        # ENTRY LOGIC — need ALL confluences
        # ========================
        long_score = 0
        short_score = 0
        long_reasons = []
        short_reasons = []

        # --- 1. VWAP BIAS (must agree) ---
        if data['above_vwap'] is not None:
            if data['above_vwap']:
                long_score += 1
                long_reasons.append(f"Above VWAP ${data['vwap']:,.0f}")
            else:
                short_score += 1
                short_reasons.append(f"Below VWAP ${data['vwap']:,.0f}")

        # --- 2. CVD DIRECTION (must be clear) ---
        buy_pct = data['cvd_buy_pct']
        if buy_pct > 60:
            long_score += 2
            long_reasons.append(f"Buy pressure {buy_pct:.0f}%")
        elif buy_pct < 40:
            short_score += 2
            short_reasons.append(f"Sell pressure {100-buy_pct:.0f}%")

        # --- 3. CVD SPIKE (confirmation) ---
        spike = data['cvd_spike']
        if spike['spike']:
            if spike['direction'] == 'BUY':
                long_score += 1
                long_reasons.append(f"CVD spike BUY {spike['ratio']}x")
            else:
                short_score += 1
                short_reasons.append(f"CVD spike SELL {spike['ratio']}x")

        # --- 4. ORDER BOOK (confirmation) ---
        imb = data['imbalance']
        if imb['bias'] in ('STRONG_BID',):
            long_score += 1
            long_reasons.append(f"OB strong bid ({imb['imbalance']:+.0f}%)")
        elif imb['bias'] in ('STRONG_ASK',):
            short_score += 1
            short_reasons.append(f"OB strong ask ({imb['imbalance']:+.0f}%)")

        # --- 5. LEVEL PROXIMITY (bonus, not required) ---
        if data['near_poc']:
            # Add to whichever side is stronger
            if long_score > short_score:
                long_score += 1
                long_reasons.append(f"Near POC ${data['poc']:,.0f}")
            elif short_score > long_score:
                short_score += 1
                short_reasons.append(f"Near POC ${data['poc']:,.0f}")

        # ========================
        # DECISION
        # ========================
        # Need score >= 4, and both sides must clearly favor one direction
        if long_score >= 4 and long_score > short_score + 1:
            sl_pct, tp_pct = self._calc_sl_tp(data, 'LONG')
            return {
                'signal': 'ENTRY', 'direction': 'LONG',
                'score': long_score, 'reasons': long_reasons,
                'sl_pct': sl_pct, 'tp_pct': tp_pct,
                'filters': filters, 'data': data
            }
        elif short_score >= 4 and short_score > long_score + 1:
            sl_pct, tp_pct = self._calc_sl_tp(data, 'SHORT')
            return {
                'signal': 'ENTRY', 'direction': 'SHORT',
                'score': short_score, 'reasons': short_reasons,
                'sl_pct': sl_pct, 'tp_pct': tp_pct,
                'filters': filters, 'data': data
            }
        else:
            return {
                'signal': 'WAIT',
                'long_score': long_score, 'short_score': short_score,
                'filters': filters, 'data': data
            }

    def _calc_sl_tp(self, data, direction):
        """Wider SL/TP — more room to breathe"""
        price = data['price']

        # Minimum 0.3% SL — not too tight
        sl_pct = 0.30
        # TP minimum 1.5x SL
        tp_pct = 0.45

        # Jika ada HVN, SL di luar node
        if data.get('near_hvn'):
            hvn_dist = abs(price - data['near_hvn']) / price * 100
            sl_pct = max(sl_pct, hvn_dist + 0.15)

        # TP = 1.5x SL minimum
        tp_pct = max(tp_pct, sl_pct * 1.5)

        return round(sl_pct, 3), round(tp_pct, 3)

    def format_analysis(self, data):
        if not data:
            return "No data available"
        lines = []
        lines.append(f"💰 Price: ${data['price']:,.2f}")
        lines.append(f"📊 CVD: {data['cvd']:+.2f} (Buy: {data['cvd_buy_pct']:.0f}%)")
        if data['cvd_spike']['spike']:
            lines.append(f"  ⚡ SPIKE {data['cvd_spike']['direction']} ({data['cvd_spike']['ratio']}x)")
        lines.append(f"📈 VWAP: ${data['vwap']:,.2f} {'⬆️' if data['above_vwap'] else '⬇️'}")
        lines.append(f"🎯 POC: ${data['poc']:,.2f}")
        lines.append(f"📋 OB: {data['imbalance']['bias']} ({data['imbalance']['imbalance']:+.1f}%)")
        lines.append(f"🏦 OI: {data['oi']['trend']} ({data['oi']['change_pct']:+.1f}%)")
        return '\n'.join(lines)


